-- =============================================================================
-- V3_18__seed_business_data.sql
-- 业务模块测试种子数据
-- 按依赖顺序插入 13 组数据：sys_dept → sys_user → asset_category → location → manufacturer → vendor → asset → idle_asset_notice → work_order → maintenance_record → retirement_application → approval_process → approval_record → asset_compensation
-- 所有 INSERT 使用 ON DUPLICATE KEY UPDATE 保证幂等（基于主键 ID 冲突检测）
-- 本迁移文件为可重复执行迁移，不包含 USE ams_db; 以保持与现有迁移文件一致
-- =============================================================================

-- =============================================================================
-- 1. sys_dept — 7 个业务部门（父级 id=1 '总公司' 已在 schema.sql 中创建）
-- =============================================================================
ON DUPLICATE KEY UPDATE dept_name = VALUES(dept_name), leader = VALUES(leader), phone = VALUES(phone), description = VALUES(description);

-- =============================================================================
-- 2. sys_user — 14 个业务用户（密码统一为 BCrypt 加密的 '123456'）
-- =============================================================================
ON DUPLICATE KEY UPDATE real_name = VALUES(real_name), email = VALUES(email), phone = VALUES(phone), dept_id = VALUES(dept_id);

-- =============================================================================
-- 3. asset_category — 11 个资产分类
-- =============================================================================
ON DUPLICATE KEY UPDATE category_name = VALUES(category_name), description = VALUES(description);

-- =============================================================================
-- 4. location — 11 个位置
-- =============================================================================
ON DUPLICATE KEY UPDATE name = VALUES(name), description = VALUES(description);

-- =============================================================================
-- 5. manufacturer — 7 个制造商
-- =============================================================================
ON DUPLICATE KEY UPDATE name = VALUES(name), contact = VALUES(contact), phone = VALUES(phone), email = VALUES(email);

-- =============================================================================
-- 6. vendor — 7 个供应商
-- =============================================================================
ON DUPLICATE KEY UPDATE name = VALUES(name), contact_person = VALUES(contact_person), contact_phone = VALUES(contact_phone), contact_email = VALUES(contact_email);


-- =============================================================================
-- 7. asset — 50 条资产（分散在北京、上海、深圳等城市，坐标非零）
-- =============================================================================
ON DUPLICATE KEY UPDATE asset_name = VALUES(asset_name), status = VALUES(status), dept_id = VALUES(dept_id), current_value = VALUES(current_value);


-- =============================================================================
-- 8. idle_asset_notice — 11 条闲置公告
-- =============================================================================
ON DUPLICATE KEY UPDATE title = VALUES(title), status = VALUES(status), claim_status = VALUES(claim_status);

-- =============================================================================
-- 9. work_order — 20 个工单
-- =============================================================================
ON DUPLICATE KEY UPDATE title = VALUES(title), status = VALUES(status), assignee_id = VALUES(assignee_id);

-- =============================================================================
-- 10. maintenance_record — 20 条维保记录
-- =============================================================================
ON DUPLICATE KEY UPDATE maintenance_type = VALUES(maintenance_type), result = VALUES(result), content = VALUES(content);

-- =============================================================================
-- 11. retirement_application — 7 个退役申请
-- =============================================================================
ON DUPLICATE KEY UPDATE status = VALUES(status), reason = VALUES(reason);

-- =============================================================================
-- 12. approval_process — 8 个审批流程
-- =============================================================================
ON DUPLICATE KEY UPDATE status = VALUES(status), current_step = VALUES(current_step);

-- =============================================================================
-- 13. approval_record — 6 条审批记录
-- =============================================================================
ON DUPLICATE KEY UPDATE approve_result = VALUES(approve_result), approve_opinion = VALUES(approve_opinion);

-- =============================================================================
-- 14. asset_compensation — 5 条资产赔偿
-- =============================================================================
ON DUPLICATE KEY UPDATE description = VALUES(description), compensation_amount = VALUES(compensation_amount), status = VALUES(status);

-- =============================================================================
-- 15. sys_user_role — 为新用户绑定角色
-- =============================================================================
ON DUPLICATE KEY UPDATE role_id = VALUES(role_id);

-- =============================================================================
-- 16. contract — 8 个合同
-- =============================================================================
ON DUPLICATE KEY UPDATE contract_name = VALUES(contract_name), status = VALUES(status), amount = VALUES(amount);

-- =============================================================================
-- 17. software_license — 8 个软件许可证
-- =============================================================================
ON DUPLICATE KEY UPDATE license_name = VALUES(license_name), status = VALUES(status), expiry_date = VALUES(expiry_date);

-- =============================================================================
-- 18. notification — 15 条通知
-- =============================================================================
ON DUPLICATE KEY UPDATE title = VALUES(title), content = VALUES(content);

-- =============================================================================
-- 19. inventory_task — 3 个盘点任务 + inventory_detail — 15 条盘点明细
-- =============================================================================
ON DUPLICATE KEY UPDATE task_name = VALUES(task_name), status = VALUES(status), scanned_count = VALUES(scanned_count);

ON DUPLICATE KEY UPDATE status = VALUES(status), actual_location = VALUES(actual_location);
